public class MemoryDemo {
    static int staticVar = 100;  // Method Area (Metaspace)

    public static void main(String[] args) {
        int localInt = 42;           // Stack: primitive value
        String localRef = "Hello";   // Stack: reference; Heap: String object
        int[] arr = {1, 2, 3};       // Stack: reference; Heap: array object

        System.out.println("localInt: " + localInt);
        System.out.println("localRef: " + localRef);
        System.out.println("arr[0]: " + arr[0]);
        System.out.println("staticVar: " + staticVar);

        modifyArray(arr);
        System.out.println("After modify: arr[0] = " + arr[0]);
    }

    static void modifyArray(int[] array) {
        // 'array' is a new reference on this method's stack frame
        // but it points to the SAME heap object as 'arr'
        array[0] = 999;
    }
}

public class GCEligibility {
    String name;

    GCEligibility(String name) {
        this.name = name;
        System.out.println("Created: " + name);
    }

    public static void main(String[] args) {
        // Case 1: Set reference to null
        GCEligibility obj1 = new GCEligibility("Object-1");
        obj1 = null;  // Object-1 is now GC eligible

        // Case 2: Reassign reference
        GCEligibility obj2 = new GCEligibility("Object-2");
        obj2 = new GCEligibility("Object-3"); // Object-2 is now GC eligible

        // Case 3: Scope ends
        createTemporary(); // Object created inside is GC eligible after return

        // Case 4: Object-3 is still reachable through obj2
        System.out.println("Still alive: " + obj2.name);

        // At this point:
        // GC eligible: Object-1, Object-2, Object-Temp
        // Still alive: Object-3 (through obj2)

        System.gc(); // Request GC (not guaranteed)
        System.out.println("Requested GC");
    }

    static void createTemporary() {
        GCEligibility temp = new GCEligibility("Object-Temp");
        // temp goes out of scope when method returns
    }
}

public class MemoryErrors {
    // Causes StackOverflowError
    static void infiniteRecursion(int depth) {
        System.out.println("Depth: " + depth);
        infiniteRecursion(depth + 1); // Never returns -> stack frames pile up
    }

    // Causes OutOfMemoryError
    static void fillHeap() {
        java.util.List<byte[]> list = new java.util.ArrayList<>();
        while (true) {
            list.add(new byte[1_000_000]); // 1 MB each, never released
        }
    }

    public static void main(String[] args) {
        // Demonstrate StackOverflowError
        try {
            infiniteRecursion(1);
        } catch (StackOverflowError e) {
            System.out.println("\nStackOverflowError caught!");
            System.out.println("Stack is exhausted by too many method frames.");
        }

        // Demonstrate OutOfMemoryError
        // Uncomment to test (will crash the JVM):
        // try {
        //     fillHeap();
        // } catch (OutOfMemoryError e) {
        //     System.out.println("OutOfMemoryError: " + e.getMessage());
        // }

        System.out.println("\nRuntime memory info:");
        Runtime rt = Runtime.getRuntime();
        System.out.println("Max memory: " + rt.maxMemory() / (1024*1024) + " MB");
        System.out.println("Total memory: " + rt.totalMemory() / (1024*1024) + " MB");
        System.out.println("Free memory: " + rt.freeMemory() / (1024*1024) + " MB");
    }
}

import java.lang.ref.WeakReference;
import java.lang.ref.SoftReference;

public class ReferenceTypes {
    public static void main(String[] args) {
        // Strong reference
        String strong = new String("Strong Reference");
        System.out.println("Strong: " + strong);
        // Object is NOT collected as long as 'strong' exists

        // Weak reference
        WeakReference<String> weak = new WeakReference<>(new String("Weak Reference"));
        System.out.println("Weak before GC: " + weak.get());
        System.gc();
        System.out.println("Weak after GC: " + weak.get()); // likely null

        // Soft reference
        SoftReference<byte[]> soft = new SoftReference<>(new byte[1_000_000]);
        System.out.println("Soft before GC: " + (soft.get() != null ? "alive" : "collected"));
        System.gc();
        System.out.println("Soft after GC: " + (soft.get() != null ? "alive" : "collected"));
        // Soft references are only collected when memory is low

        // Weak reference with a strong backup
        String data = new String("Shared Data");
        WeakReference<String> weakRef = new WeakReference<>(data);
        System.out.println("\nWeak with strong backup: " + weakRef.get());
        System.gc();
        System.out.println("After GC (strong still exists): " + weakRef.get());
        data = null; // remove strong reference
        System.gc();
        System.out.println("After removing strong ref: " + weakRef.get());
    }
}

import java.util.ArrayList;
import java.util.List;

public class MemoryLeakDemo {
    // THIS IS THE LEAK: static list that only grows, never shrinks
    private static final List<byte[]> cache = new ArrayList<>();

    static void addToCache() {
        cache.add(new byte[100_000]); // 100 KB per entry
    }

    public static void main(String[] args) {
        Runtime rt = Runtime.getRuntime();

        System.out.println("=== Memory Leak Demonstration ===");
        long initialFree = rt.freeMemory();

        for (int i = 0; i < 100; i++) {
            addToCache();
        }

        System.gc();
        long afterFree = rt.freeMemory();
        System.out.println("Cache size: " + cache.size() + " entries");
        System.out.println("Memory consumed: " + (initialFree - afterFree) / 1024 + " KB");
        System.out.println("GC cannot help because the static list holds all references.");

        // Fix: clear the cache when data is no longer needed
        cache.clear();
        System.gc();
        long afterClear = rt.freeMemory();
        System.out.println("\nAfter clearing cache:");
        System.out.println("Cache size: " + cache.size());
        System.out.println("Memory recovered: " + (afterClear - afterFree) / 1024 + " KB");
    }
}

public class MemoryStats {
    public static void main(String[] args) {
        Runtime rt = Runtime.getRuntime();

        System.out.println("=== JVM Memory Statistics ===");
        printMemory(rt, "Initial state");

        // Allocate some objects
        Object[] objects = new Object[100_000];
        for (int i = 0; i < objects.length; i++) {
            objects[i] = new byte[100]; // 100 bytes each
        }
        printMemory(rt, "After allocating 100K objects");

        // Make objects eligible for GC
        for (int i = 0; i < objects.length; i++) {
            objects[i] = null;
        }
        printMemory(rt, "After nullifying references");

        // Request garbage collection
        System.gc();
        printMemory(rt, "After System.gc()");

        System.out.println("\nAvailable processors: " + rt.availableProcessors());
    }

    static void printMemory(Runtime rt, String label) {
        long max = rt.maxMemory() / (1024 * 1024);
        long total = rt.totalMemory() / (1024 * 1024);
        long free = rt.freeMemory() / (1024 * 1024);
        long used = total - free;
        System.out.printf("%s:%n  Max=%dMB, Total=%dMB, Used=%dMB, Free=%dMB%n",
                          label, max, total, used, free);
    }
}

